import { readdirSync, readFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { describe, expect, it } from "vitest";
import { FRAMEWORKS } from "./frameworks.js";
// repoRoot/bitfab-plugin-lib/src/flows -> repoRoot
const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "../../..");
const tsSrcDir = resolve(repoRoot, "bitfab-typescript-sdk/src");
const pySrcDir = resolve(repoRoot, "bitfab-python-sdk/bitfab");
// Concatenate every (non-test) source file in a tree so symbol checks are
// resilient to which file a symbol lives in. This is a tripwire, not a parser:
// it fails loudly the moment one language ships a framework capability the
// other drops (the exact class of drift unit tests can't otherwise see, since
// you can't write a test for a method that does not exist). When it fails,
// either restore parity or, if the divergence is intentional, update the table
// below with a comment explaining why.
function readAllSource(dir, exts, excludeSuffixes) {
    const entries = readdirSync(dir, { recursive: true });
    let out = "";
    for (const rel of entries) {
        if (!exts.some((e) => rel.endsWith(e))) {
            continue;
        }
        if (excludeSuffixes.some((s) => rel.endsWith(s))) {
            continue;
        }
        out += `${readFileSync(resolve(dir, rel), "utf8")}\n`;
    }
    return out;
}
// Strip comments and docstrings before symbol checks so a symbol that survives
// ONLY in a comment, a JSDoc example, or a Python docstring can't mask the fact
// that its implementation was removed (e.g. dropping the `on_collector` param
// while leaving its docstring mentions). Conservative: only whole-line `//` /
// `#` comments are removed (inline `https://` / `#` after code is left alone),
// plus block comments and triple-quoted strings.
function stripTsComments(src) {
    return src.replace(/\/\*[\s\S]*?\*\//g, "").replace(/^\s*\/\/.*$/gm, "");
}
function stripPyComments(src) {
    return src
        .replace(/"""[\s\S]*?"""/g, "")
        .replace(/'''[\s\S]*?'''/g, "")
        .replace(/^\s*#.*$/gm, "");
}
const tsSrc = stripTsComments(readAllSource(tsSrcDir, [".ts"], [".test.ts", ".d.ts"]));
const pySrc = stripPyComments(readAllSource(pySrcDir, [".py"], ["_test.py"]));
const tsHas = (symbol) => tsSrc.includes(symbol);
// Python methods are matched as definitions (`def name(`) so a stray mention in
// a comment or docstring can't mask a removed implementation. The trailing `(`
// anchors the name so a prefix can't satisfy a longer sibling's check (e.g.
// `def wrap_run(` must NOT be matched by `def wrap_run_streamed(`).
const pyHasDef = (name) => pySrc.includes(`def ${name}(`);
const pyHas = (symbol) => pySrc.includes(symbol);
describe("SDK cross-language parity", () => {
    it("reads both SDK source trees", () => {
        expect(tsSrc.length).toBeGreaterThan(0);
        expect(pySrc.length).toBeGreaterThan(0);
    });
    // Every framework handler/alias/root-wrapper named in the registry must be
    // implemented in BOTH the TS and Python SDKs. The registry is the single
    // source of truth the flows render from; if a name there is missing from a
    // SDK, the docs/plugin would advertise a method that does not exist.
    describe.each(FRAMEWORKS.map((f) => [f.id, f]))("%s registry methods exist in both SDKs", (_id, f) => {
        // TypeScript-only frameworks (e.g. the Vercel AI SDK) have no `py` method;
        // parity is only enforced for the languages the registry declares.
        it(`handler ${f.handler.ts}${f.handler.py ? ` / ${f.handler.py}` : ""}`, () => {
            expect(tsHas(f.handler.ts), `TS missing ${f.handler.ts}`).toBe(true);
            if (f.handler.py) {
                expect(pyHasDef(f.handler.py), `Python missing def ${f.handler.py}`).toBe(true);
            }
        });
        if (f.aliasHandler) {
            const alias = f.aliasHandler;
            it(`aliasHandler ${alias.ts}${alias.py ? ` / ${alias.py}` : ""}`, () => {
                expect(tsHas(alias.ts), `TS missing ${alias.ts}`).toBe(true);
                if (alias.py) {
                    expect(pyHasDef(alias.py), `Python missing def ${alias.py}`).toBe(true);
                }
            });
        }
        if (f.rootWrapper) {
            const wrapper = f.rootWrapper;
            it(`rootWrapper ${wrapper.ts}${wrapper.py ? ` / ${wrapper.py}` : ""}`, () => {
                expect(tsHas(wrapper.ts), `TS missing ${wrapper.ts}`).toBe(true);
                if (wrapper.py) {
                    expect(pyHasDef(wrapper.py), `Python missing def ${wrapper.py}`).toBe(true);
                }
            });
        }
    });
    // Method-level capabilities the registry does NOT model (sub-methods and
    // options on the handlers). Each entry lists the evidence symbols that must
    // appear in each language. These are the exact gaps the framework audit
    // found (Python lacked wrap_run_streamed and on_collector while TS had the
    // streaming overload and onCollector); this table keeps them from recurring.
    const CAPABILITY_PARITY = [
        {
            name: "OpenAI Agents replayable run wrapper (wrapRun / wrap_run)",
            ts: ["wrapRun"],
            pyDefs: ["wrap_run"],
        },
        {
            // TS streams via wrapRun's `stream` option (RunOptions.stream); Python
            // exposes a dedicated wrap_run_streamed async generator.
            name: "OpenAI Agents streamed run wrapper",
            ts: ["stream", "wrapRun"],
            pyDefs: ["wrap_run_streamed"],
        },
        {
            name: "Claude Agent SDK instrument + stream wrap",
            ts: ["instrumentOptions", "wrapQuery", "wrapResponse"],
            pyDefs: ["instrument_options", "wrap_query", "wrap_response"],
        },
        {
            // BAML Collector access: TS onCollector option + .collector attribute;
            // Python on_collector param + .collector attribute.
            name: "BAML Collector access (onCollector / on_collector)",
            ts: ["onCollector"],
            pySymbols: ["on_collector"],
        },
    ];
    it.each(CAPABILITY_PARITY.map((c) => [c.name, c]))("%s exists in both SDKs", (_name, cap) => {
        for (const s of cap.ts) {
            expect(tsHas(s), `TS missing ${s}`).toBe(true);
        }
        for (const d of cap.pyDefs ?? []) {
            expect(pyHasDef(d), `Python missing def ${d}`).toBe(true);
        }
        for (const s of cap.pySymbols ?? []) {
            expect(pyHas(s), `Python missing ${s}`).toBe(true);
        }
    });
});
